import { useEffect, useRef } from 'react';
import type { Dispatch, MutableRefObject, RefObject, SetStateAction } from 'react';
import type { DragCoordinator } from '@/tools/video-editor/hooks/useDragCoordinator';
import type { TrackKind } from '@/tools/video-editor/types';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import { snapDrag } from '@/tools/video-editor/lib/snap-edges';

const DRAG_THRESHOLD_PX = 4;
/** Snap threshold in pixels — converted to seconds based on current zoom. */
const SNAP_THRESHOLD_PX = 8;

export interface ActionDragState {
  rowId: string;
  initialStart: number;
  initialEnd: number;
  latestStart: number;
  latestEnd: number;
}

interface UseCrossTrackDragOptions {
  timelineWrapperRef: RefObject<HTMLDivElement | null>;
  dataRef: MutableRefObject<TimelineData | null>;
  moveClipToRow: (clipId: string, targetRowId: string, newStartTime?: number) => void;
  createTrackAndMoveClip: (clipId: string, kind: TrackKind, newStartTime?: number) => void;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  coordinator: DragCoordinator;
  rowHeight: number;
  scale: number;
  scaleWidth: number;
  startLeft: number;
}

interface DragSession {
  pointerId: number;
  clipId: string;
  sourceRowId: string;
  sourceKind: TrackKind;
  startClientX: number;
  startClientY: number;
  pointerOffsetX: number;
  pointerOffsetY: number;
  latestStart: number;
  clipDuration: number;
  clipEl: HTMLElement;
  moveListener: (event: PointerEvent) => void;
  upListener: (event: PointerEvent) => void;
  cancelListener: (event: PointerEvent) => void;
  /** Floating clone shown during cross-track drag. */
  floatingGhostEl: HTMLElement | null;
  hasMoved: boolean;
}

export const useClipDrag = ({
  timelineWrapperRef,
  dataRef,
  moveClipToRow,
  createTrackAndMoveClip,
  setSelectedClipId,
  setSelectedTrackId,
  coordinator,
  rowHeight,
  scale,
  scaleWidth,
  startLeft,
}: UseCrossTrackDragOptions): void => {
  const dragSessionRef = useRef<DragSession | null>(null);
  const actionDragStateRef = useRef<ActionDragState | null>(null);
  const crossTrackActiveRef = useRef(false);

  // Keep volatile values in refs so the effect doesn't re-run mid-drag
  // when zoom/scale changes.
  const coordinatorRef = useRef(coordinator);
  coordinatorRef.current = coordinator;
  const scaleRef = useRef(scale);
  scaleRef.current = scale;
  const scaleWidthRef = useRef(scaleWidth);
  scaleWidthRef.current = scaleWidth;
  const moveClipToRowRef = useRef(moveClipToRow);
  moveClipToRowRef.current = moveClipToRow;
  const createTrackAndMoveClipRef = useRef(createTrackAndMoveClip);
  createTrackAndMoveClipRef.current = createTrackAndMoveClip;
  const setSelectedClipIdRef = useRef(setSelectedClipId);
  setSelectedClipIdRef.current = setSelectedClipId;
  const setSelectedTrackIdRef = useRef(setSelectedTrackId);
  setSelectedTrackIdRef.current = setSelectedTrackId;

  useEffect(() => {
    const clearSession = (session: DragSession | null, deferDeactivate = false) => {
      coordinatorRef.current.end();
      if (!session) {
        actionDragStateRef.current = null;
        if (!deferDeactivate) {
          crossTrackActiveRef.current = false;
        }
        return;
      }

      session.floatingGhostEl?.remove();
      window.removeEventListener('pointermove', session.moveListener);
      window.removeEventListener('pointerup', session.upListener);
      window.removeEventListener('pointercancel', session.cancelListener);
      try {
        if (session.clipEl.hasPointerCapture(session.pointerId)) {
          session.clipEl.releasePointerCapture(session.pointerId);
        }
      } catch {
        // Pointer capture can already be released by the browser during teardown.
      }

      dragSessionRef.current = null;
      actionDragStateRef.current = null;
      if (deferDeactivate) {
        window.requestAnimationFrame(() => {
          if (!dragSessionRef.current) {
            crossTrackActiveRef.current = false;
          }
        });
      } else {
        crossTrackActiveRef.current = false;
      }
    };

    // ── Helpers ──────────────────────────────────────────────────────

    const updateFloatingGhostPosition = (session: DragSession, event: PointerEvent) => {
      if (!session.floatingGhostEl) return;
      session.floatingGhostEl.style.left = `${event.clientX - session.pointerOffsetX}px`;
      session.floatingGhostEl.style.top = `${event.clientY - session.pointerOffsetY}px`;
    };

    const createFloatingGhost = (clipEl: HTMLElement): HTMLElement => {
      const rect = clipEl.getBoundingClientRect();
      const el = clipEl.cloneNode(true) as HTMLElement;
      el.classList.add('cross-track-ghost');
      el.style.width = `${rect.width}px`;
      el.style.height = `${rect.height}px`;
      document.body.appendChild(el);
      return el;
    };

    // ── Pointer handlers ─────────────────────────────────────────────

    const handlePointerDown = (event: PointerEvent) => {
      if (event.button !== 0) return;

      // Check that the event originated inside our wrapper
      const wrapper = timelineWrapperRef.current;
      if (!wrapper || !wrapper.contains(event.target as Node)) return;

      const clipTarget = event.target instanceof HTMLElement ? event.target.closest<HTMLElement>('.clip-action') : null;
      if (!clipTarget || (event.target instanceof HTMLElement && event.target.closest("[data-delete-clip='true']"))) return;

      const clipId = clipTarget.dataset.clipId;
      const rowId = clipTarget.dataset.rowId;
      if (!clipId || !rowId) return;

      const current = dataRef.current;
      const sourceTrack = current?.tracks.find((track) => track.id === rowId);
      const sourceRow = current?.rows.find((row) => row.id === rowId);
      const sourceAction = sourceRow?.actions.find((action) => action.id === clipId);
      if (!current || !sourceTrack || !sourceAction) return;

      clearSession(dragSessionRef.current);

      const clipRect = clipTarget.getBoundingClientRect();
      const initialStart = sourceAction.start;
      const clipDuration = sourceAction.end - sourceAction.start;
      actionDragStateRef.current = {
        rowId,
        initialStart,
        initialEnd: sourceAction.end,
        latestStart: initialStart,
        latestEnd: sourceAction.end,
      };

      const handlePointerMove = (moveEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || moveEvent.pointerId !== session.pointerId) return;

        const dx = moveEvent.clientX - session.startClientX;
        const dy = moveEvent.clientY - session.startClientY;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Don't show anything until the pointer actually moves (avoids flash on click)
        if (!session.hasMoved && distance < DRAG_THRESHOLD_PX) return;

        // First move past threshold — capture the pointer so we own all subsequent events
        // and the timeline library can't start its own competing drag.
        if (!session.hasMoved) {
          session.hasMoved = true;
          try { session.clipEl.setPointerCapture(session.pointerId); } catch { /* ok */ }
        }

        // Prevent default on all moves once dragging to stop the library's handler
        moveEvent.preventDefault();

        const nextPosition = coordinatorRef.current.update({
          clientX: moveEvent.clientX,
          clientY: moveEvent.clientY,
          sourceKind: session.sourceKind,
          clipDuration: session.clipDuration,
          clipOffsetX: session.pointerOffsetX,
        });

        // Snap to sibling clip edges on the target row
        const pixelsPerSecond = scaleWidthRef.current / scaleRef.current;
        const snapThresholdS = SNAP_THRESHOLD_PX / pixelsPerSecond;
        const targetRowId = nextPosition.trackId ?? session.sourceRowId;
        const targetRow = dataRef.current?.rows.find((r) => r.id === targetRowId);
        const siblings = targetRow?.actions ?? [];
        const { start: snappedStart } = snapDrag(
          nextPosition.time,
          session.clipDuration,
          siblings,
          session.clipId,
          snapThresholdS,
        );

        session.latestStart = snappedStart;
        const dragState = actionDragStateRef.current;
        if (dragState) {
          const dur = dragState.initialEnd - dragState.initialStart;
          dragState.latestStart = snappedStart;
          dragState.latestEnd = snappedStart + dur;
        }

        // Activate cross-track mode (floating ghost) on vertical threshold
        if (!crossTrackActiveRef.current && Math.abs(dy) >= 10) {
          crossTrackActiveRef.current = true;
          session.floatingGhostEl = createFloatingGhost(session.clipEl);
          updateFloatingGhostPosition(session, moveEvent);
        }

        if (crossTrackActiveRef.current) {
          updateFloatingGhostPosition(session, moveEvent);
        }

        if (session.floatingGhostEl) {
          session.floatingGhostEl.style.cursor = nextPosition.isReject ? 'not-allowed' : '';
        }
      };

      const handlePointerUp = (upEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || upEvent.pointerId !== session.pointerId) return;

        const dropPosition = coordinatorRef.current.lastPosition;
        // Use snapped time from drag state (computed during pointermove) rather than
        // the raw coordinator time, which doesn't account for edge snapping.
        const nextStart = actionDragStateRef.current?.latestStart ?? session.latestStart;
        if (crossTrackActiveRef.current) {
          upEvent.preventDefault();
          if (dropPosition?.isNewTrack) {
            createTrackAndMoveClipRef.current(session.clipId, session.sourceKind, nextStart);
          } else if (dropPosition?.trackId && !dropPosition.isReject) {
            moveClipToRowRef.current(session.clipId, dropPosition.trackId, nextStart);
            setSelectedTrackIdRef.current(dropPosition.trackId);
          } else {
            moveClipToRowRef.current(session.clipId, session.sourceRowId, nextStart);

            moveClipToRowRef.current(session.clipId, session.sourceRowId, nextStart);
            setSelectedTrackIdRef.current(session.sourceRowId);
          }
          setSelectedClipIdRef.current(session.clipId);
          clearSession(session, true);
          return;
        }

        // Same-row move — apply the horizontal position change
        if (session.hasMoved) {
          moveClipToRowRef.current(session.clipId, session.sourceRowId, nextStart);
        }
        setSelectedClipIdRef.current(session.clipId);
        setSelectedTrackIdRef.current(session.sourceRowId);
        clearSession(session);
      };

      const handlePointerCancel = (cancelEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || cancelEvent.pointerId !== session.pointerId) return;
        clearSession(session);
      };

      dragSessionRef.current = {
        pointerId: event.pointerId,
        clipId,
        sourceRowId: rowId,
        sourceKind: sourceTrack.kind,
        startClientX: event.clientX,
        startClientY: event.clientY,
        pointerOffsetX: event.clientX - clipRect.left,
        pointerOffsetY: event.clientY - clipRect.top,
        latestStart: initialStart,
        clipDuration,
        clipEl: clipTarget,
        moveListener: handlePointerMove,
        upListener: handlePointerUp,
        cancelListener: handlePointerCancel,
        floatingGhostEl: null,
        hasMoved: false,
      };

      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
      window.addEventListener('pointercancel', handlePointerCancel);
    };

    const handleBlur = () => {
      clearSession(dragSessionRef.current);
    };

    // Use capture phase on document so this fires BEFORE ClipAction's stopPropagation.
    // We listen on document (not the wrapper) because the wrapper may not be mounted
    // yet when this effect first runs; the containment check inside handlePointerDown
    // scopes events to the correct wrapper.
    document.addEventListener('pointerdown', handlePointerDown, true);
    window.addEventListener('blur', handleBlur);
    return () => {
      document.removeEventListener('pointerdown', handlePointerDown, true);
      window.removeEventListener('blur', handleBlur);
      clearSession(dragSessionRef.current);
    };
  // Stable refs only — volatile values (scale, coordinator, etc.) are read via refs
  // so the effect never re-runs mid-drag.
  }, [dataRef, timelineWrapperRef]);
};

import { useEffect } from 'react';
import { isEditableTarget } from '@/tools/video-editor/lib/coordinate-utils';

interface UseKeyboardShortcutsOptions {
  hasSelectedClip: boolean;
  moveSelectedClipToTrack: (direction: 'up' | 'down') => void;
  togglePlayPause: () => void;
  seekRelative: (deltaSeconds: number) => void;
  toggleMute: () => void;
  splitSelectedClip: () => void;
  deleteSelectedClip: () => void;
  clearSelection: () => void;
}

export function useKeyboardShortcuts({
  hasSelectedClip,
  moveSelectedClipToTrack,
  togglePlayPause,
  seekRelative,
  toggleMute,
  splitSelectedClip,
  deleteSelectedClip,
  clearSelection,
}: UseKeyboardShortcutsOptions) {
  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      if (isEditableTarget(event.target)) {
        return;
      }

      if (event.key === 'ArrowLeft') {
        event.preventDefault();
        seekRelative(-1);
        return;
      }

      if (event.key === 'ArrowRight') {
        event.preventDefault();
        seekRelative(1);
        return;
      }

      if (event.key === 'ArrowUp' && hasSelectedClip) {
        event.preventDefault();
        moveSelectedClipToTrack('up');
        return;
      }

      if (event.key === 'ArrowDown' && hasSelectedClip) {
        event.preventDefault();
        moveSelectedClipToTrack('down');
        return;
      }

      if (event.code === 'Space') {
        event.preventDefault();
        togglePlayPause();
        return;
      }

      if (event.key.toLowerCase() === 'm' && hasSelectedClip) {
        event.preventDefault();
        toggleMute();
        return;
      }

      if (event.key.toLowerCase() === 's' && hasSelectedClip) {
        event.preventDefault();
        splitSelectedClip();
        return;
      }

      if ((event.key === 'Backspace' || event.key === 'Delete') && hasSelectedClip) {
        event.preventDefault();
        deleteSelectedClip();
        return;
      }

      if (event.key === 'Escape') {
        event.preventDefault();
        clearSelection();
      }
    };

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [clearSelection, deleteSelectedClip, hasSelectedClip, moveSelectedClipToTrack, seekRelative, splitSelectedClip, toggleMute, togglePlayPause]);
}

import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

/** Default snap threshold in seconds — overridden at call site based on zoom. */
const DEFAULT_THRESHOLD_S = 0.15;

/**
 * Collect all edge times (start and end) from actions on a row,
 * excluding the action being moved/resized.
 */
const collectEdges = (siblings: TimelineAction[], excludeId: string): number[] => {
  const edges: number[] = [0]; // always snap to timeline start
  for (const action of siblings) {
    if (action.id === excludeId) continue;
    edges.push(action.start, action.end);
  }
  return edges;
};

/**
 * Find the nearest edge within the threshold.
 * Returns the edge time if within threshold, otherwise returns the original value.
 */
const snapValue = (value: number, edges: number[], threshold: number): number => {
  let best = value;
  let bestDist = threshold;
  for (const edge of edges) {
    const dist = Math.abs(value - edge);
    if (dist < bestDist) {
      bestDist = dist;
      best = edge;
    }
  }
  return best;
};

export interface SnapDragResult {
  start: number;
  snapped: boolean;
}

/**
 * Snap a dragged clip's start time so that its start or end aligns
 * with a sibling clip's start or end edge.
 */
export const snapDrag = (
  proposedStart: number,
  clipDuration: number,
  siblings: TimelineAction[],
  excludeId: string,
  thresholdSeconds = DEFAULT_THRESHOLD_S,
): SnapDragResult => {
  const edges = collectEdges(siblings, excludeId);
  const proposedEnd = proposedStart + clipDuration;

  // Try snapping start edge
  const snappedStart = snapValue(proposedStart, edges, thresholdSeconds);
  if (snappedStart !== proposedStart) {
    return { start: snappedStart, snapped: true };
  }

  // Try snapping end edge
  const snappedEnd = snapValue(proposedEnd, edges, thresholdSeconds);
  if (snappedEnd !== proposedEnd) {
    return { start: snappedEnd - clipDuration, snapped: true };
  }

  return { start: proposedStart, snapped: false };
};

export interface SnapResizeResult {
  start: number;
  end: number;
  snapped: boolean;
}

/**
 * Snap a resize edge so it aligns with a sibling clip's start or end.
 */
export const snapResize = (
  proposedStart: number,
  proposedEnd: number,
  dir: 'left' | 'right',
  siblings: TimelineAction[],
  excludeId: string,
  thresholdSeconds = DEFAULT_THRESHOLD_S,
): SnapResizeResult => {
  const edges = collectEdges(siblings, excludeId);

  if (dir === 'left') {
    const snapped = snapValue(proposedStart, edges, thresholdSeconds);
    return { start: snapped, end: proposedEnd, snapped: snapped !== proposedStart };
  }

  const snapped = snapValue(proposedEnd, edges, thresholdSeconds);
  return { start: proposedStart, end: snapped, snapped: snapped !== proposedEnd };
};

import { useCallback, useLayoutEffect, useRef, useState } from 'react';

export interface SelectClipOptions {
  toggle?: boolean;
}

export interface UseMultiSelectResult {
  selectedClipIds: ReadonlySet<string>;
  selectedClipIdsRef: React.MutableRefObject<Set<string>>;
  primaryClipId: string | null;
  selectClip: (clipId: string, opts?: SelectClipOptions) => void;
  selectClips: (clipIds: Iterable<string>) => void;
  addToSelection: (clipIds: Iterable<string>) => void;
  clearSelection: () => void;
  isClipSelected: (clipId: string) => boolean;
  pruneSelection: (validIds: Set<string>) => void;
}

const getFirstSetValue = (values: ReadonlySet<string>): string | null => {
  for (const value of values) {
    return value;
  }

  return null;
};

const getPrimaryClipId = (
  selectedClipIds: ReadonlySet<string>,
  preferredPrimaryClipId: string | null,
): string | null => {
  if (preferredPrimaryClipId && selectedClipIds.has(preferredPrimaryClipId)) {
    return preferredPrimaryClipId;
  }

  return getFirstSetValue(selectedClipIds);
};

const areSetsEqual = (left: ReadonlySet<string>, right: ReadonlySet<string>): boolean => {
  if (left.size !== right.size) {
    return false;
  }

  for (const value of left) {
    if (!right.has(value)) {
      return false;
    }
  }

  return true;
};

const buildSelectionSet = (clipIds: Iterable<string>): Set<string> => {
  const nextSelection = new Set<string>();

  for (const clipId of clipIds) {
    nextSelection.add(clipId);
  }

  return nextSelection;
};

export function useMultiSelect(): UseMultiSelectResult {
  const [selectedClipIdsState, setSelectedClipIdsState] = useState<Set<string>>(() => new Set());
  const [primaryClipIdState, setPrimaryClipIdState] = useState<string | null>(null);

  const selectedClipIdsRef = useRef<Set<string>>(selectedClipIdsState);
  const primaryClipIdRef = useRef<string | null>(primaryClipIdState);

  useLayoutEffect(() => {
    selectedClipIdsRef.current = selectedClipIdsState;
    primaryClipIdRef.current = primaryClipIdState;
  }, [primaryClipIdState, selectedClipIdsState]);

  const commitSelection = useCallback((nextSelection: Set<string>, nextPrimaryClipId: string | null) => {
    selectedClipIdsRef.current = nextSelection;
    primaryClipIdRef.current = nextPrimaryClipId;
    setSelectedClipIdsState(nextSelection);
    setPrimaryClipIdState(nextPrimaryClipId);
  }, []);

  const clearSelection = useCallback(() => {
    if (selectedClipIdsRef.current.size === 0 && primaryClipIdRef.current === null) {
      return;
    }

    commitSelection(new Set(), null);
  }, [commitSelection]);

  const selectClip = useCallback((clipId: string, opts?: SelectClipOptions) => {
    if (!opts?.toggle) {
      commitSelection(new Set([clipId]), clipId);
      return;
    }

    const nextSelection = new Set(selectedClipIdsRef.current);
    if (nextSelection.has(clipId)) {
      nextSelection.delete(clipId);
      commitSelection(
        nextSelection,
        getPrimaryClipId(
          nextSelection,
          primaryClipIdRef.current === clipId ? null : primaryClipIdRef.current,
        ),
      );
      return;
    }

    nextSelection.add(clipId);
    commitSelection(nextSelection, clipId);
  }, [commitSelection]);

  const selectClips = useCallback((clipIds: Iterable<string>) => {
    const nextSelection = buildSelectionSet(clipIds);
    commitSelection(nextSelection, getPrimaryClipId(nextSelection, null));
  }, [commitSelection]);

  const addToSelection = useCallback((clipIds: Iterable<string>) => {
    const nextSelection = new Set(selectedClipIdsRef.current);
    for (const clipId of clipIds) {
      nextSelection.add(clipId);
    }

    const nextPrimaryClipId = getPrimaryClipId(nextSelection, primaryClipIdRef.current);
    if (
      areSetsEqual(selectedClipIdsRef.current, nextSelection)
      && primaryClipIdRef.current === nextPrimaryClipId
    ) {
      return;
    }

    commitSelection(nextSelection, nextPrimaryClipId);
  }, [commitSelection]);

  const isClipSelected = useCallback((clipId: string) => {
    return selectedClipIdsRef.current.has(clipId);
  }, []);

  const pruneSelection = useCallback((validIds: Set<string>) => {
    const nextSelection = new Set<string>();
    for (const clipId of selectedClipIdsRef.current) {
      if (validIds.has(clipId)) {
        nextSelection.add(clipId);
      }
    }

    const nextPrimaryClipId = getPrimaryClipId(nextSelection, primaryClipIdRef.current);
    if (
      areSetsEqual(selectedClipIdsRef.current, nextSelection)
      && primaryClipIdRef.current === nextPrimaryClipId
    ) {
      return;
    }

    commitSelection(nextSelection, nextPrimaryClipId);
  }, [commitSelection]);

  return {
    selectedClipIds: selectedClipIdsState,
    selectedClipIdsRef,
    primaryClipId: primaryClipIdState,
    selectClip,
    selectClips,
    addToSelection,
    clearSelection,
    isClipSelected,
    pruneSelection,
  };
}

import type { TimelineAction, TimelineRow } from '@/tools/video-editor/types/timeline-canvas';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';

/** Minimum clip duration in seconds — below this the move is rejected. */
const MIN_CLIP_DURATION = 0.05;

export interface OverlapResult {
  /** Updated rows with the moved clip trimmed to fit. */
  rows: TimelineRow[];
  /** Metadata patch for the moved clip if its source-time `from`/`to` changed. */
  metaPatches: Record<string, Partial<ClipMeta>>;
}

export interface GroupMovedClip {
  rowId: string;
  clipId: string;
  newStart: number;
  newEnd: number;
}

/**
 * Find the largest gap that contains or is nearest to `preferred` within the
 * range [0, ∞). Siblings are treated as immovable obstacles.
 */
function findBestGap(
  preferred: number,
  duration: number,
  siblings: TimelineAction[],
): { start: number; end: number } | null {
  // Build sorted list of occupied intervals
  const occupied = siblings
    .map((s) => ({ start: s.start, end: s.end }))
    .sort((a, b) => a.start - b.start);

  // Build gaps between occupied intervals (including 0..first and last..∞)
  const gaps: Array<{ start: number; end: number }> = [];
  let cursor = 0;
  for (const occ of occupied) {
    if (occ.start > cursor) {
      gaps.push({ start: cursor, end: occ.start });
    }
    cursor = Math.max(cursor, occ.end);
  }
  // Gap from last sibling to infinity
  gaps.push({ start: cursor, end: Infinity });

  if (gaps.length === 0) return null;

  // Find the gap that contains the preferred start, or the nearest one
  let bestGap = gaps[0];
  let bestDistance = Infinity;

  for (const gap of gaps) {
    // If preferred start falls in this gap
    if (preferred >= gap.start && preferred < gap.end) {
      bestGap = gap;
      bestDistance = 0;
      break;
    }

    // Distance from preferred to gap
    const dist = preferred < gap.start
      ? gap.start - preferred
      : preferred - gap.end;
    if (dist < bestDistance) {
      bestDistance = dist;
      bestGap = gap;
    }
  }

  return bestGap;
}

function findBestGroupStart(
  preferred: number,
  duration: number,
  siblings: TimelineAction[],
): number | null {
  const occupied = siblings
    .map((sibling) => ({ start: sibling.start, end: sibling.end }))
    .sort((left, right) => left.start - right.start);

  const gaps: Array<{ start: number; end: number }> = [];
  let cursor = 0;
  for (const interval of occupied) {
    if (interval.start > cursor) {
      gaps.push({ start: cursor, end: interval.start });
    }
    cursor = Math.max(cursor, interval.end);
  }
  gaps.push({ start: cursor, end: Infinity });

  let bestStart: number | null = null;
  let bestDistance = Infinity;

  for (const gap of gaps) {
    if (gap.end !== Infinity && gap.end - gap.start < duration) {
      continue;
    }

    const maxStart = gap.end === Infinity ? Infinity : gap.end - duration;
    const candidateStart = preferred < gap.start
      ? gap.start
      : preferred > maxStart
        ? maxStart
        : preferred;
    const distance = Math.abs(candidateStart - preferred);

    if (distance < bestDistance) {
      bestDistance = distance;
      bestStart = candidateStart;
    }
  }

  return bestStart;
}

/**
 * Trim the **moved/resized clip** so it doesn't overlap any existing siblings
 * on the same row. Existing clips are treated as immovable; the moved clip is
 * the one that gives way.
 *
 * Strategy: find the gap (between siblings) that the clip's requested start
 * falls into, then clamp the clip to fit within that gap.
 */
export function resolveOverlaps(
  rows: TimelineRow[],
  rowId: string,
  clipId: string,
  meta: Record<string, ClipMeta>,
): OverlapResult {
  const metaPatches: Record<string, Partial<ClipMeta>> = {};

  const nextRows = rows.map((row) => {
    if (row.id !== rowId) return row;

    const movedAction = row.actions.find((a) => a.id === clipId);
    if (!movedAction) return row;

    const siblings = row.actions.filter((a) => a.id !== clipId);

    // Check if there's actually any overlap
    const hasOverlap = siblings.some(
      (sib) => movedAction.start < sib.end && movedAction.end > sib.start,
    );
    if (!hasOverlap) return row;

    const clipMeta = meta[clipId];
    const speed = clipMeta?.speed ?? 1;
    const duration = movedAction.end - movedAction.start;

    const gap = findBestGap(movedAction.start, duration, siblings);
    if (!gap) return row;

    // Clamp clip to fit within the gap
    let start = Math.max(movedAction.start, gap.start);
    let end = gap.end === Infinity
      ? start + duration
      : Math.min(start + duration, gap.end);

    // If clamping end pushed duration below threshold, try starting at gap.start
    if (end - start < MIN_CLIP_DURATION && gap.end !== Infinity) {
      start = gap.start;
      end = Math.min(gap.start + duration, gap.end);
    }

    // Still too small — reject the move (return row unchanged)
    if (end - start < MIN_CLIP_DURATION) {
      return row;
    }

    // Update source-time metadata if start changed (for timed clips)
    if (start !== movedAction.start && clipMeta && typeof clipMeta.hold !== 'number') {
      const trimmedSeconds = start - movedAction.start;
      metaPatches[clipId] = {
        ...metaPatches[clipId],
        from: (clipMeta.from ?? 0) + trimmedSeconds * speed,
      };
    }

    // Update source-time metadata if end changed
    if (end !== movedAction.end && clipMeta && typeof clipMeta.hold !== 'number') {
      const from = metaPatches[clipId]?.from ?? clipMeta.from ?? 0;
      metaPatches[clipId] = {
        ...metaPatches[clipId],
        to: from + (end - start) * speed,
      };
    }

    const trimmedAction = { ...movedAction, start, end };
    return {
      ...row,
      actions: row.actions.map((a) => (a.id === clipId ? trimmedAction : a)),
    };
  });

  return { rows: nextRows, metaPatches };
}

export function resolveGroupOverlaps(
  rows: TimelineRow[],
  movedClips: GroupMovedClip[],
  _meta: Record<string, ClipMeta>,
): TimelineRow[] {
  if (movedClips.length === 0) {
    return rows;
  }

  const movedClipsByRow = new Map<string, GroupMovedClip[]>();
  for (const movedClip of movedClips) {
    const existing = movedClipsByRow.get(movedClip.rowId);
    if (existing) {
      existing.push(movedClip);
    } else {
      movedClipsByRow.set(movedClip.rowId, [movedClip]);
    }
  }

  const nextRowsById = new Map<string, TimelineRow>();

  for (const [rowId, rowMovedClips] of movedClipsByRow) {
    const row = rows.find((candidate) => candidate.id === rowId);
    if (!row) {
      return rows;
    }

    const movedClipIds = new Set(rowMovedClips.map((clip) => clip.clipId));
    const movedActionsById = new Map(
      row.actions
        .filter((action) => movedClipIds.has(action.id))
        .map((action) => [action.id, action]),
    );

    if (movedActionsById.size !== rowMovedClips.length) {
      return rows;
    }

    const preferredStart = Math.min(...rowMovedClips.map((clip) => clip.newStart));
    const preferredEnd = Math.max(...rowMovedClips.map((clip) => clip.newEnd));
    const groupDuration = preferredEnd - preferredStart;
    const siblings = row.actions.filter((action) => !movedClipIds.has(action.id));
    const groupStart = findBestGroupStart(preferredStart, groupDuration, siblings);

    if (groupStart === null) {
      return rows;
    }

    const delta = groupStart - preferredStart;
    const movedUpdates = new Map(
      rowMovedClips.map((clip) => {
        const currentAction = movedActionsById.get(clip.clipId);
        if (!currentAction) {
          return [clip.clipId, null] as const;
        }

        return [
          clip.clipId,
          {
            ...currentAction,
            start: clip.newStart + delta,

            start: clip.newStart + delta,
            end: clip.newEnd + delta,
          },
        ] as const;
      }),
    );

    if ([...movedUpdates.values()].some((value) => value === null)) {
      return rows;
    }

    nextRowsById.set(rowId, {
      ...row,
      actions: row.actions.map((action) => movedUpdates.get(action.id) ?? action),
    });
  }

  return rows.map((row) => nextRowsById.get(row.id) ?? row);
}

