  startLeft,
}: UseCrossTrackDragOptions): void => {
  const dragSessionRef = useRef<DragSession | null>(null);
  const actionDragStateRef = useRef<ActionDragState | null>(null);
  const crossTrackActiveRef = useRef(false);

  // Keep volatile values in refs so the effect doesn't re-run mid-drag
  // when zoom/scale changes.
  const coordinatorRef = useRef(coordinator);
  coordinatorRef.current = coordinator;
  const scaleRef = useRef(scale);
  scaleRef.current = scale;
  const scaleWidthRef = useRef(scaleWidth);
  scaleWidthRef.current = scaleWidth;
  const moveClipToRowRef = useRef(moveClipToRow);
  moveClipToRowRef.current = moveClipToRow;
  const createTrackAndMoveClipRef = useRef(createTrackAndMoveClip);
  createTrackAndMoveClipRef.current = createTrackAndMoveClip;
  const setSelectedClipIdRef = useRef(setSelectedClipId);
  setSelectedClipIdRef.current = setSelectedClipId;
  const setSelectedTrackIdRef = useRef(setSelectedTrackId);
  setSelectedTrackIdRef.current = setSelectedTrackId;

  useEffect(() => {
    const clearSession = (session: DragSession | null, deferDeactivate = false) => {
      coordinatorRef.current.end();
      if (!session) {
        actionDragStateRef.current = null;
        if (!deferDeactivate) {
          crossTrackActiveRef.current = false;
        }
        return;
      }

      session.floatingGhostEl?.remove();
      window.removeEventListener('pointermove', session.moveListener);
      window.removeEventListener('pointerup', session.upListener);
      window.removeEventListener('pointercancel', session.cancelListener);
      try {
        if (session.clipEl.hasPointerCapture(session.pointerId)) {
          session.clipEl.releasePointerCapture(session.pointerId);
        }
      } catch {
        // Pointer capture can already be released by the browser during teardown.
      }

      dragSessionRef.current = null;
      actionDragStateRef.current = null;
      if (deferDeactivate) {
        window.requestAnimationFrame(() => {
          if (!dragSessionRef.current) {
            crossTrackActiveRef.current = false;
          }
        });
      } else {
        crossTrackActiveRef.current = false;
      }
    };

    // ── Helpers ──────────────────────────────────────────────────────

    const updateFloatingGhostPosition = (session: DragSession, event: PointerEvent) => {
      if (!session.floatingGhostEl) return;
      session.floatingGhostEl.style.left = `${event.clientX - session.pointerOffsetX}px`;
      session.floatingGhostEl.style.top = `${event.clientY - session.pointerOffsetY}px`;
    };

    const createFloatingGhost = (clipEl: HTMLElement): HTMLElement => {
      const rect = clipEl.getBoundingClientRect();
      const el = clipEl.cloneNode(true) as HTMLElement;
      el.classList.add('cross-track-ghost');
      el.style.width = `${rect.width}px`;
      el.style.height = `${rect.height}px`;
      document.body.appendChild(el);
      return el;
    };

    // ── Pointer handlers ─────────────────────────────────────────────

    const handlePointerDown = (event: PointerEvent) => {
      if (event.button !== 0) return;

      // Check that the event originated inside our wrapper
      const wrapper = timelineWrapperRef.current;
      if (!wrapper || !wrapper.contains(event.target as Node)) return;

      const clipTarget = event.target instanceof HTMLElement ? event.target.closest<HTMLElement>('.clip-action') : null;
      if (!clipTarget || (event.target instanceof HTMLElement && event.target.closest("[data-delete-clip='true']"))) return;

      const clipId = clipTarget.dataset.clipId;
      const rowId = clipTarget.dataset.rowId;
      if (!clipId || !rowId) return;

      const current = dataRef.current;
      const sourceTrack = current?.tracks.find((track) => track.id === rowId);
      const sourceRow = current?.rows.find((row) => row.id === rowId);
      const sourceAction = sourceRow?.actions.find((action) => action.id === clipId);
      if (!current || !sourceTrack || !sourceAction) return;

      clearSession(dragSessionRef.current);

      const clipRect = clipTarget.getBoundingClientRect();
      const initialStart = sourceAction.start;
      const clipDuration = sourceAction.end - sourceAction.start;
      actionDragStateRef.current = {
        rowId,
        initialStart,
        initialEnd: sourceAction.end,
        latestStart: initialStart,
        latestEnd: sourceAction.end,
      };

      const handlePointerMove = (moveEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || moveEvent.pointerId !== session.pointerId) return;

        const dx = moveEvent.clientX - session.startClientX;
        const dy = moveEvent.clientY - session.startClientY;
        const distance = Math.sqrt(dx * dx + dy * dy);

        // Don't show anything until the pointer actually moves (avoids flash on click)
        if (!session.hasMoved && distance < DRAG_THRESHOLD_PX) return;

        // First move past threshold — capture the pointer so we own all subsequent events
        // and the timeline library can't start its own competing drag.
        if (!session.hasMoved) {
          session.hasMoved = true;
          try { session.clipEl.setPointerCapture(session.pointerId); } catch { /* ok */ }
        }

        // Prevent default on all moves once dragging to stop the library's handler
        moveEvent.preventDefault();

        const nextPosition = coordinatorRef.current.update({
          clientX: moveEvent.clientX,
          clientY: moveEvent.clientY,
          sourceKind: session.sourceKind,
          clipDuration: session.clipDuration,
          clipOffsetX: session.pointerOffsetX,
        });

        // Snap to sibling clip edges on the target row
        const pixelsPerSecond = scaleWidthRef.current / scaleRef.current;
        const snapThresholdS = SNAP_THRESHOLD_PX / pixelsPerSecond;
        const targetRowId = nextPosition.trackId ?? session.sourceRowId;
        const targetRow = dataRef.current?.rows.find((r) => r.id === targetRowId);
        const siblings = targetRow?.actions ?? [];
        const { start: snappedStart } = snapDrag(
          nextPosition.time,
          session.clipDuration,
          siblings,
          session.clipId,
          snapThresholdS,
        );

        session.latestStart = snappedStart;
        const dragState = actionDragStateRef.current;
        if (dragState) {
          const dur = dragState.initialEnd - dragState.initialStart;
          dragState.latestStart = snappedStart;
          dragState.latestEnd = snappedStart + dur;
        }

        // Activate cross-track mode (floating ghost) on vertical threshold
        if (!crossTrackActiveRef.current && Math.abs(dy) >= 10) {
          crossTrackActiveRef.current = true;
          session.floatingGhostEl = createFloatingGhost(session.clipEl);
          updateFloatingGhostPosition(session, moveEvent);
        }

        if (crossTrackActiveRef.current) {
          updateFloatingGhostPosition(session, moveEvent);
        }

        if (session.floatingGhostEl) {
          session.floatingGhostEl.style.cursor = nextPosition.isReject ? 'not-allowed' : '';
        }
      };

      const handlePointerUp = (upEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || upEvent.pointerId !== session.pointerId) return;

        const dropPosition = coordinatorRef.current.lastPosition;
        // Use snapped time from drag state (computed during pointermove) rather than
        // the raw coordinator time, which doesn't account for edge snapping.
        const nextStart = actionDragStateRef.current?.latestStart ?? session.latestStart;
        if (crossTrackActiveRef.current) {
          upEvent.preventDefault();
          if (dropPosition?.isNewTrack) {
            createTrackAndMoveClipRef.current(session.clipId, session.sourceKind, nextStart);
          } else if (dropPosition?.trackId && !dropPosition.isReject) {
            moveClipToRowRef.current(session.clipId, dropPosition.trackId, nextStart);
            setSelectedTrackIdRef.current(dropPosition.trackId);
          } else {
            moveClipToRowRef.current(session.clipId, session.sourceRowId, nextStart);
            setSelectedTrackIdRef.current(session.sourceRowId);
          }
          setSelectedClipIdRef.current(session.clipId);
          clearSession(session, true);
          return;
        }

        // Same-row move — apply the horizontal position change
        if (session.hasMoved) {
          moveClipToRowRef.current(session.clipId, session.sourceRowId, nextStart);
        }
        setSelectedClipIdRef.current(session.clipId);
        setSelectedTrackIdRef.current(session.sourceRowId);
        clearSession(session);
      };

      const handlePointerCancel = (cancelEvent: PointerEvent) => {
        const session = dragSessionRef.current;
        if (!session || cancelEvent.pointerId !== session.pointerId) return;
        clearSession(session);
      };

      dragSessionRef.current = {
        pointerId: event.pointerId,
        clipId,
        sourceRowId: rowId,
        sourceKind: sourceTrack.kind,
        startClientX: event.clientX,
        startClientY: event.clientY,
        pointerOffsetX: event.clientX - clipRect.left,
        pointerOffsetY: event.clientY - clipRect.top,
        latestStart: initialStart,
        clipDuration,
        clipEl: clipTarget,
        moveListener: handlePointerMove,
        upListener: handlePointerUp,
        cancelListener: handlePointerCancel,
        floatingGhostEl: null,
        hasMoved: false,
      };

      window.addEventListener('pointermove', handlePointerMove);
      window.addEventListener('pointerup', handlePointerUp);
      window.addEventListener('pointercancel', handlePointerCancel);
    };

    const handleBlur = () => {
      clearSession(dragSessionRef.current);
    };

    // Use capture phase on document so this fires BEFORE ClipAction's stopPropagation.
    // We listen on document (not the wrapper) because the wrapper may not be mounted
    // yet when this effect first runs; the containment check inside handlePointerDown
    // scopes events to the correct wrapper.
    document.addEventListener('pointerdown', handlePointerDown, true);
    window.addEventListener('blur', handleBlur);
    return () => {
      document.removeEventListener('pointerdown', handlePointerDown, true);
      window.removeEventListener('blur', handleBlur);
      clearSession(dragSessionRef.current);
    };
  // Stable refs only — volatile values (scale, coordinator, etc.) are read via refs
  // so the effect never re-runs mid-drag.
  }, [dataRef, timelineWrapperRef]);
};

import { memo, useCallback, useLayoutEffect, useMemo, useRef } from 'react';
import '@/tools/video-editor/components/TimelineEditor/timeline-overrides.css';
import { ClipAction } from '@/tools/video-editor/components/TimelineEditor/ClipAction';
import { DropIndicator } from '@/tools/video-editor/components/TimelineEditor/DropIndicator';
import { TimelineCanvas } from '@/tools/video-editor/components/TimelineEditor/TimelineCanvas';
import { TrackLabel } from '@/tools/video-editor/components/TimelineEditor/TrackLabel';
import { ROW_HEIGHT, TIMELINE_START_LEFT } from '@/tools/video-editor/lib/coordinate-utils';
import { useTimelineEditorContext } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { useClipDrag } from '@/tools/video-editor/hooks/useClipDrag';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

function TimelineEditorComponent() {
  const {
    data,
    resolvedConfig,
    timelineRef,
    timelineWrapperRef,
    dataRef,
    moveClipToRow,
    createTrackAndMoveClip,
    setSelectedClipId,
    setSelectedTrackId,
    scale,
    scaleWidth,
    coordinator,
    indicatorRef,
    editAreaRef,
    selectedClipId,
    selectedTrackId,
    handleTrackPopoverChange,
    handleReorderTrack,
    handleRemoveTrack,
    handleSplitClipAtTime,
    handleDeleteClip,
    onCursorDrag,
    onClickTimeArea,
    onActionResizeStart,
    onActionResizeEnd,
    onTimelineDragOver,
    onTimelineDragLeave,
    onTimelineDrop,
    onDoubleClickAsset,
  } = useTimelineEditorContext();
  const trackListRef = useRef<HTMLDivElement>(null);

  // useClipDrag handles all internal clip drag interactions (horizontal moves,
  // cross-track moves, and new-track creation) using the same fixed-position
  // drop indicators as external HTML5 drag-drop.
  useClipDrag({
    timelineWrapperRef,
    dataRef,
    moveClipToRow,
    createTrackAndMoveClip,
    setSelectedClipId,
    setSelectedTrackId,
    coordinator,
    rowHeight: ROW_HEIGHT,
    scale,
    scaleWidth,
    startLeft: TIMELINE_START_LEFT,
  });

  useLayoutEffect(() => {
    const wrapper = timelineWrapperRef.current;
    const nextEditArea = wrapper?.querySelector<HTMLElement>('.timeline-canvas-edit-area') ?? null;
    editAreaRef.current = nextEditArea;

    return () => {
      if (editAreaRef.current === nextEditArea) {
        editAreaRef.current = null;
      }
    };
  }, [data, editAreaRef, timelineWrapperRef]);

  const scaleCount = useMemo(() => {
    if (!data) {
      return 1;
    }

    let maxEnd = 0;
    for (const row of data.rows) {
      for (const action of row.actions) {
        maxEnd = Math.max(maxEnd, action.end);
      }
    }

    return Math.ceil((maxEnd + 20) / scale) + 1;
  }, [data, scale]);

  const thumbnailMap = useMemo<Record<string, string>>(() => {
    if (!resolvedConfig) {
      return {};
    }

    return resolvedConfig.clips.reduce<Record<string, string>>((acc, clip) => {
      if (clip.clipType === 'text' || !clip.assetEntry?.type?.startsWith('image')) {
        return acc;
      }

      acc[clip.id] = clip.assetEntry.src;
      return acc;
    }, {});
  }, [resolvedConfig]);

  const handleClipSelect = useCallback((clipId: string, trackId: string) => {
    setSelectedClipId(clipId);
    setSelectedTrackId(trackId);
  }, [setSelectedClipId, setSelectedTrackId]);

  const pixelsPerSecond = scaleWidth / scale;

  const clientXToTime = useCallback((clientX: number): number => {
    const wrapper = timelineWrapperRef.current;
    if (!wrapper) return 0;
    const editArea = wrapper.querySelector<HTMLElement>('.timeline-canvas-edit-area');
    const grid = editArea;
    const rect = (editArea ?? wrapper).getBoundingClientRect();
    const scrollLeft = grid?.scrollLeft ?? 0;
    return Math.max(0, (clientX - rect.left + scrollLeft - TIMELINE_START_LEFT) / pixelsPerSecond);
  }, [pixelsPerSecond, timelineWrapperRef]);

  const handleSplitClipHere = useCallback((clipId: string, clientX: number) => {
    const time = clientXToTime(clientX);
    handleSplitClipAtTime(clipId, time);
  }, [clientXToTime, handleSplitClipAtTime]);

  const getActionRender = useCallback((action: TimelineAction) => {
    const clipMeta = data?.meta[action.id];
    if (!clipMeta) {
      return null;
    }

    const clipWidthPx = (action.end - action.start) * pixelsPerSecond;
    const thumbnailSrc = clipWidthPx >= 40 ? thumbnailMap[action.id] : undefined;

    return (
      <ClipAction
        action={action}
        clipMeta={clipMeta}
        isSelected={selectedClipId === action.id}
        thumbnailSrc={thumbnailSrc}
        onSelect={handleClipSelect}
        onDoubleClickAsset={onDoubleClickAsset}
        onSplitHere={handleSplitClipHere}
        onDeleteClip={handleDeleteClip}
      />
    );
  }, [data, handleClipSelect, handleDeleteClip, handleSplitClipHere, onDoubleClickAsset, pixelsPerSecond, selectedClipId, thumbnailMap]);

  const kindCountMap = useMemo(() => {
    if (!data) {
      return {} as Record<string, number>;
    }

    return data.tracks.reduce<Record<string, number>>((counts, track) => {
      counts[track.kind] = (counts[track.kind] ?? 0) + 1;
      return counts;
    }, {});
  }, [data]);

  if (!data) {
    return null;
  }

  return (
    <div className="flex h-full overflow-hidden rounded-xl border border-border bg-card/80">
      <div
        ref={trackListRef}
        className="flex w-36 shrink-0 flex-col overflow-y-auto border-r border-border pt-[30px]"
        onScroll={(event) => {
          timelineRef.current?.setScrollTop(event.currentTarget.scrollTop);
        }}
      >
        {data.tracks.map((track, index) => {
          const row = data.rows[index];
          return (
            <TrackLabel
              key={track.id}
              track={track}
              isSelected={selectedTrackId === track.id}
              trackCount={data.tracks.length}
              trackIndex={index}
              sameKindCount={kindCountMap[track.kind] ?? 0}
              hasClips={Boolean(row && row.actions.length > 0)}
              onSelect={setSelectedTrackId}
              onChange={handleTrackPopoverChange}
              onReorder={handleReorderTrack}
              onRemove={handleRemoveTrack}
            />
          );
        })}
      </div>
      <div
        ref={timelineWrapperRef}
        className="timeline-wrapper relative min-w-0 flex-1 overflow-hidden"
        onDragOver={onTimelineDragOver}
        onDragLeave={onTimelineDragLeave}
        onDrop={onTimelineDrop}
      >
        <TimelineCanvas
          ref={timelineRef}
          rows={data.rows}
          scale={scale}
          scaleWidth={scaleWidth}
          scaleSplitCount={5}
          startLeft={TIMELINE_START_LEFT}
          rowHeight={ROW_HEIGHT}
          minScaleCount={scaleCount}
          maxScaleCount={scaleCount}
          getActionRender={getActionRender}
          onCursorDrag={onCursorDrag}
          onClickTimeArea={onClickTimeArea}
          onActionResizeStart={onActionResizeStart}
          onActionResizeEnd={onActionResizeEnd}
          trackLabelRef={trackListRef}
        />
        <DropIndicator ref={indicatorRef} editAreaRef={editAreaRef} />
      </div>
    </div>
  );
}

export const TimelineEditor = memo(TimelineEditorComponent);

import { useCallback, useLayoutEffect, useRef } from 'react';
import type { Dispatch, MutableRefObject, SetStateAction } from 'react';
import {
  getVisualTracks,
  splitClipAtPlayhead,
  toggleClipMute,
  updateClipInConfig,
} from '@/tools/video-editor/lib/editor-utils';
import {
  updateClipOrder,
} from '@/tools/video-editor/lib/coordinate-utils';
import {
  getNextClipId,
  type ClipMeta,
  type TimelineData,
} from '@/tools/video-editor/lib/timeline-data';
import type { UseTimelineDataResult } from '@/tools/video-editor/hooks/useTimelineData';
import type { TimelineAction } from '@/tools/video-editor/types/timeline-canvas';

export interface UseClipEditingArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  resolvedConfig: TimelineData['resolvedConfig'] | null;
  selectedClipId: string | null;
  selectedTrack: UseTimelineDataResult['selectedTrack'];
  currentTime: number;
  setSelectedClipId: Dispatch<SetStateAction<string | null>>;
  setSelectedTrackId: Dispatch<SetStateAction<string | null>>;
  applyTimelineEdit: UseTimelineDataResult['applyTimelineEdit'];
  applyResolvedConfigEdit: UseTimelineDataResult['applyResolvedConfigEdit'];
}

export interface UseClipEditingResult {
  onOverlayChange: (actionId: string, patch: Partial<ClipMeta>) => void;
  handleDeleteClip: (clipId: string) => void;
  handleSelectedClipChange: (patch: Partial<ClipMeta> & { at?: number }) => void;
  handleResetClipPosition: () => void;
  handleSplitSelectedClip: () => void;
  handleSplitClipAtTime: (clipId: string, timeSeconds: number) => void;
  handleToggleMute: () => void;
  handleAddText: () => void;
}

export function useClipEditing({
  dataRef,
  resolvedConfig,
  selectedClipId,
  selectedTrack,
  currentTime,
  setSelectedClipId,
  setSelectedTrackId,
  applyTimelineEdit,
  applyResolvedConfigEdit,
}: UseClipEditingArgs): UseClipEditingResult {
  const currentTimeRef = useRef(currentTime);

  useLayoutEffect(() => {
    currentTimeRef.current = currentTime;
  }, [currentTime]);

  const onOverlayChange = useCallback((actionId: string, patch: Partial<ClipMeta>) => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    applyTimelineEdit(current.rows, { [actionId]: patch });
  }, [applyTimelineEdit, dataRef]);

  const handleDeleteClip = useCallback((clipId: string) => {
    if (clipId.startsWith('uploading-')) {
      return;
    }

    const current = dataRef.current;
    if (!current) {
      return;
    }

    const nextRows = current.rows.map((row) => ({
      ...row,
      actions: row.actions.filter((action) => action.id !== clipId),
    }));
    applyTimelineEdit(nextRows, undefined, [clipId]);
    if (selectedClipId === clipId) {
      setSelectedClipId(null);
    }
  }, [applyTimelineEdit, dataRef, selectedClipId, setSelectedClipId]);

  const handleSelectedClipChange = useCallback((patch: Partial<ClipMeta> & { at?: number }) => {
    const current = dataRef.current;
    if (!current || !selectedClipId) {
      return;
    }

    const clipRow = current.rows.find((row) => row.actions.some((action) => action.id === selectedClipId));
    if (!clipRow) {
      return;
    }

    const nextRows = current.rows.map((row) => {
      if (row.id !== clipRow.id || patch.at === undefined) {
        return row;
      }

      return {
        ...row,
        actions: row.actions.map((action) => {
          if (action.id !== selectedClipId) {
            return action;
          }

          const duration = action.end - action.start;
          return {
            ...action,
            start: patch.at,
            end: patch.at + duration,
          };
        }),
      };
    });

    const { at: _at, ...metaPatch } = patch;
    applyTimelineEdit(nextRows, { [selectedClipId]: metaPatch });
  }, [applyTimelineEdit, dataRef, selectedClipId]);

  const handleResetClipPosition = useCallback(() => {
    if (!selectedClipId || !resolvedConfig) {
      return;
    }

    const nextConfig = updateClipInConfig(resolvedConfig, selectedClipId, (clip) => ({
      ...clip,
      x: undefined,
      y: undefined,
      width: undefined,
      height: undefined,
      cropTop: undefined,
      cropBottom: undefined,
      cropLeft: undefined,
      cropRight: undefined,
    }));
    applyResolvedConfigEdit(nextConfig, { selectedClipId });
  }, [applyResolvedConfigEdit, resolvedConfig, selectedClipId]);

  const handleSplitSelectedClip = useCallback(() => {
    if (!selectedClipId || !resolvedConfig) {
      return;
    }

    const splitResult = splitClipAtPlayhead(resolvedConfig, selectedClipId, currentTimeRef.current);
    if (!splitResult.nextSelectedClipId) {
      return;
    }

    applyResolvedConfigEdit(splitResult.config, { selectedClipId: splitResult.nextSelectedClipId });
  }, [applyResolvedConfigEdit, resolvedConfig, selectedClipId]);

  const handleSplitClipAtTime = useCallback((clipId: string, timeSeconds: number) => {
    if (!resolvedConfig) {
      return;
    }

    const splitResult = splitClipAtPlayhead(resolvedConfig, clipId, timeSeconds);
    if (!splitResult.nextSelectedClipId) {
      return;
    }

    applyResolvedConfigEdit(splitResult.config, { selectedClipId: splitResult.nextSelectedClipId });
  }, [applyResolvedConfigEdit, resolvedConfig]);

  const handleToggleMute = useCallback(() => {
    if (!selectedClipId || !resolvedConfig) {
      return;
    }

    const nextConfig = toggleClipMute(resolvedConfig, selectedClipId);
    applyResolvedConfigEdit(nextConfig, { selectedClipId });
  }, [applyResolvedConfigEdit, resolvedConfig, selectedClipId]);

  const handleAddText = useCallback(() => {
    const current = dataRef.current;
    if (!current) {
      return;
    }

    const visualTrack = selectedTrack?.kind === 'visual'
      ? selectedTrack
      : getVisualTracks(current.resolvedConfig)[0];
    if (!visualTrack) {
      return;
    }

    const clipId = getNextClipId(current.meta);
    const action: TimelineAction = {
      id: clipId,
      start: currentTimeRef.current,
      end: currentTimeRef.current + 5,
      effectId: `effect-${clipId}`,
    };
    const nextRows = current.rows.map((row) => (
      row.id === visualTrack.id
        ? { ...row, actions: [...row.actions, action] }
        : row
    ));
    const nextClipOrder = updateClipOrder(current.clipOrder, visualTrack.id, (ids) => [...ids, clipId]);
    applyTimelineEdit(nextRows, {
      [clipId]: {
        track: visualTrack.id,
        clipType: 'text',
        text: {
          content: 'Double-click to edit',
          fontSize: 64,
          color: '#ffffff',
          align: 'center',
        },
        x: 120,
        y: 120,
        width: 640,
        height: 180,
        opacity: 1,
      },
    }, undefined, nextClipOrder);
    setSelectedClipId(clipId);
    setSelectedTrackId(visualTrack.id);
  }, [applyTimelineEdit, dataRef, selectedTrack, setSelectedClipId, setSelectedTrackId]);

  return {
    onOverlayChange,
    handleDeleteClip,
    handleSelectedClipChange,
    handleResetClipPosition,
    handleSplitSelectedClip,
    handleSplitClipAtTime,
    handleToggleMute,
    handleAddText,
  };
}

import { useMemo, useState } from 'react';
import { Trash2, Volume2, Wand2 } from 'lucide-react';
import { Button } from '@/shared/components/ui/button';
import { cn } from '@/shared/components/ui/contracts/cn';
import { Input } from '@/shared/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/shared/components/ui/select';
import { Slider } from '@/shared/components/ui/slider';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/shared/components/ui/tabs';
import { Textarea } from '@/shared/components/ui/textarea';
import { continuousEffectTypes, entranceEffectTypes, exitEffectTypes } from '@/tools/video-editor/effects';
import { CustomEffectEditor } from '@/tools/video-editor/components/CustomEffectEditor';
import type { ClipTab } from '@/tools/video-editor/hooks/useTimelineData';
import type { ClipMeta } from '@/tools/video-editor/lib/timeline-data';
import type { ResolvedTimelineClip, TrackDefinition } from '@/tools/video-editor/types';

interface ClipPanelProps {
  clip: ResolvedTimelineClip | null;
  track: TrackDefinition | null;
  hasPredecessor: boolean;
  onChange: (patch: Partial<ClipMeta> & { at?: number }) => void;
  onResetPosition: () => void;
  onClose: () => void;
  onDelete?: () => void;
  onToggleMute: () => void;
  compositionWidth: number;
  compositionHeight: number;
  activeTab: ClipTab;
  setActiveTab: (tab: ClipTab) => void;
}

const NO_EFFECT = '__none__';
const TAB_COLUMNS_CLASS = {
  3: 'grid-cols-3',
  4: 'grid-cols-4',
} as const;

export function getVisibleClipTabs(
  clip: ResolvedTimelineClip | null,
  track: TrackDefinition | null,
): ClipTab[] {
  if (clip?.clipType === 'text') {
    return ['effects', 'timing', 'position', 'text'];
  }

  if (track?.kind === 'audio') {
    return ['effects', 'timing', 'audio'];
  }

  return ['effects', 'timing', 'position', 'audio'];
}

function FieldLabel({ children }: { children: React.ReactNode }) {
  return <div className="text-xs font-medium text-muted-foreground">{children}</div>;
}

export function ClipPanel({
  clip,
  track,
  hasPredecessor,
  onChange,
  onResetPosition,
  onClose,
  onDelete,
  onToggleMute,
  compositionWidth,
  compositionHeight,
  activeTab,
  setActiveTab,
}: ClipPanelProps) {
  const [showCustomEditor, setShowCustomEditor] = useState(false);
  const visibleTabs = useMemo(() => getVisibleClipTabs(clip, track), [clip, track]);
  const customEffectCategory = useMemo(() => {
    if (activeTab !== 'effects') {
      return 'continuous' as const;
    }
    return (clip?.continuous?.type?.startsWith('custom:') ? 'continuous' : clip?.entrance?.type?.startsWith('custom:') ? 'entrance' : clip?.exit?.type?.startsWith('custom:') ? 'exit' : 'continuous') as const;
  }, [activeTab, clip]);

  if (!clip) {
    return (
      <div className="rounded-xl border border-dashed border-border bg-muted/30 p-4 text-sm text-muted-foreground">
        Select a clip to edit timing, position, audio, text, or effects.
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <div className="flex items-start justify-between gap-3 rounded-xl border border-border bg-card/70 p-3">
        <div className="min-w-0">
          <div className="truncate text-sm font-medium text-foreground">
            {clip.text?.content || clip.asset || clip.id}
          </div>
          <div className="mt-1 text-[11px] uppercase tracking-[0.14em] text-muted-foreground">
            {clip.clipType ?? 'media'} · {track?.label ?? clip.track}
          </div>
        </div>
        <div className="flex gap-2">
          {onDelete && (
            <Button type="button" variant="ghost" size="icon" className="h-8 w-8 text-destructive hover:text-destructive" onClick={onDelete}>
              <Trash2 className="h-4 w-4" />
            </Button>
          )}
          <Button type="button" variant="ghost" size="icon" className="h-8 w-8" onClick={onClose}>
            ×
          </Button>
        </div>
      </div>

      <Tabs value={activeTab} onValueChange={(value) => setActiveTab(value as ClipTab)}>
        <TabsList className={cn('grid w-full bg-muted/60', TAB_COLUMNS_CLASS[visibleTabs.length as keyof typeof TAB_COLUMNS_CLASS] ?? 'grid-cols-4')}>
          {visibleTabs.includes('effects') && <TabsTrigger value="effects">Effects</TabsTrigger>}
          {visibleTabs.includes('timing') && <TabsTrigger value="timing">Timing</TabsTrigger>}
          {visibleTabs.includes('position') && <TabsTrigger value="position">Position</TabsTrigger>}
          {visibleTabs.includes('audio') && <TabsTrigger value="audio">Audio</TabsTrigger>}
          {visibleTabs.includes('text') && <TabsTrigger value="text">Text</TabsTrigger>}
        </TabsList>

        {visibleTabs.includes('effects') && (
          <TabsContent value="effects" className="space-y-3">
            <div className="grid gap-3 md:grid-cols-2">
              <div className="space-y-2">
                <FieldLabel>Entrance</FieldLabel>
                <Select
                  value={clip.entrance?.type ?? NO_EFFECT}
                  onValueChange={(value) => onChange({ entrance: value === NO_EFFECT ? undefined : { type: value, duration: clip.entrance?.duration ?? 0.4 } })}
                >
                  <SelectTrigger><SelectValue placeholder="None" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value={NO_EFFECT}>None</SelectItem>
                    {entranceEffectTypes.map((effect) => <SelectItem key={effect} value={effect}>{effect}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2">
                <FieldLabel>Exit</FieldLabel>
                <Select
                  value={clip.exit?.type ?? NO_EFFECT}
                  onValueChange={(value) => onChange({ exit: value === NO_EFFECT ? undefined : { type: value, duration: clip.exit?.duration ?? 0.4 } })}
                >
                  <SelectTrigger><SelectValue placeholder="None" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value={NO_EFFECT}>None</SelectItem>
                    {exitEffectTypes.map((effect) => <SelectItem key={effect} value={effect}>{effect}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
              <div className="space-y-2 md:col-span-2">
                <FieldLabel>Continuous</FieldLabel>
                <Select
                  value={clip.continuous?.type ?? NO_EFFECT}
                  onValueChange={(value) => onChange({ continuous: value === NO_EFFECT ? undefined : { type: value, intensity: clip.continuous?.intensity ?? 0.5 } })}
                >
                  <SelectTrigger><SelectValue placeholder="None" /></SelectTrigger>
                  <SelectContent>
                    <SelectItem value={NO_EFFECT}>None</SelectItem>
                    {continuousEffectTypes.map((effect) => <SelectItem key={effect} value={effect}>{effect}</SelectItem>)}
                  </SelectContent>
                </Select>
              </div>
            </div>
            <div className="rounded-lg border border-border bg-card/70 p-3">
              <div className="mb-2 flex items-center justify-between">
                <div className="text-xs font-medium text-foreground">Custom effects</div>
                <Button type="button" size="sm" variant="secondary" className="gap-1" onClick={() => setShowCustomEditor((value) => !value)}>
                  <Wand2 className="h-3.5 w-3.5" />
                  {showCustomEditor ? 'Hide' : 'Edit'}
                </Button>
              </div>
              {showCustomEditor && (
                <CustomEffectEditor
                  category={customEffectCategory}
                  initialSlug={clip.continuous?.type?.replace(/^custom:/, '')}
                  onApply={(slug, category) => {
                    if (category === 'entrance') {
                      onChange({ entrance: { type: `custom:${slug}`, duration: clip.entrance?.duration ?? 0.4 } });
                      return;
                    }
                    if (category === 'exit') {
                      onChange({ exit: { type: `custom:${slug}`, duration: clip.exit?.duration ?? 0.4 } });
                      return;
                    }
                    onChange({ continuous: { type: `custom:${slug}`, intensity: clip.continuous?.intensity ?? 0.5 } });
                  }}
                />
              )}
            </div>
          </TabsContent>
        )}

        {visibleTabs.includes('timing') && (
          <TabsContent value="timing" className="space-y-3">
            <div className="grid gap-3 md:grid-cols-2">
              <div className="space-y-2">
                <FieldLabel>Start (seconds)</FieldLabel>
                <Input type="number" value={clip.at} onChange={(event) => onChange({ at: Number(event.target.value) })} />
              </div>
              <div className="space-y-2">
                <FieldLabel>Speed</FieldLabel>
                <Input type="number" value={clip.speed ?? 1} step="0.1" onChange={(event) => onChange({ speed: Number(event.target.value) })} />
              </div>
              <div className="space-y-2">
                <FieldLabel>Source In</FieldLabel>
                <Input type="number" value={clip.from ?? 0} step="0.1" onChange={(event) => onChange({ from: Number(event.target.value) })} />
              </div>
              <div className="space-y-2">
                <FieldLabel>Source Out</FieldLabel>
                <Input type="number" value={clip.to ?? clip.assetEntry?.duration ?? 5} step="0.1" onChange={(event) => onChange({ to: Number(event.target.value) })} />
              </div>
            </div>
          </TabsContent>
        )}

        {visibleTabs.includes('position') && (
          <TabsContent value="position" className="space-y-3">
            <div className="grid gap-3 md:grid-cols-2">
              <div className="space-y-2">
                <FieldLabel>X</FieldLabel>
                <Input type="number" value={clip.x ?? 0} onChange={(event) => onChange({ x: Number(event.target.value) })} />
              </div>
              <div className="space-y-2">
                <FieldLabel>Y</FieldLabel>
                <Input type="number" value={clip.y ?? 0} onChange={(event) => onChange({ y: Number(event.target.value) })} />
              </div>
              <div className="space-y-2">
                <FieldLabel>Width</FieldLabel>
                <Input type="number" max={compositionWidth} value={clip.width ?? compositionWidth} onChange={(event) => onChange({ width: Number(event.target.value) })} />
              </div>
              <div className="space-y-2">
                <FieldLabel>Height</FieldLabel>
                <Input type="number" max={compositionHeight} value={clip.height ?? compositionHeight} onChange={(event) => onChange({ height: Number(event.target.value) })} />
              </div>
            </div>
            <div className="space-y-2">
              <FieldLabel>Opacity</FieldLabel>
              <Slider
                value={[clip.opacity ?? 1]}
                min={0}
                max={1}
                step={0.05}
                onValueChange={(value) => onChange({ opacity: value })}
              />
            </div>
            <Button type="button" variant="outline" size="sm" onClick={onResetPosition}>
              Reset position
            </Button>
          </TabsContent>
        )}

        {visibleTabs.includes('audio') && (
          <TabsContent value="audio" className="space-y-3">
            <div className="rounded-lg border border-border bg-card/70 p-3">
              <div className="mb-2 flex items-center gap-2 text-sm text-foreground">
                <Volume2 className="h-4 w-4" />
                Volume
              </div>
              <Slider
                value={[clip.volume ?? 1]}
                min={0}
                max={1}
                step={0.05}
                onValueChange={(value) => onChange({ volume: value })}
              />
              <Button type="button" variant="secondary" size="sm" className="mt-3" onClick={onToggleMute}>
                Toggle mute
              </Button>
            </div>
          </TabsContent>
        )}

        {visibleTabs.includes('text') && (
          <TabsContent value="text" className="space-y-3">
            {clip.clipType === 'text' ? (
              <>
                <Textarea
                  value={clip.text?.content ?? ''}
                  onChange={(event) => onChange({ text: { ...(clip.text ?? { content: '' }), content: event.target.value } })}
                  rows={5}
                />
                <div className="grid gap-3 md:grid-cols-2">
                  <div className="space-y-2">
                    <FieldLabel>Font size</FieldLabel>
                    <Input
                      type="number"
                      value={clip.text?.fontSize ?? 64}
                      onChange={(event) => onChange({ text: { ...(clip.text ?? { content: '' }), fontSize: Number(event.target.value) } })}
                    />
                  </div>
                  <div className="space-y-2">
                    <FieldLabel>Color</FieldLabel>
                    <Input
                      type="color"
                      value={clip.text?.color ?? '#ffffff'}
                      onChange={(event) => onChange({ text: { ...(clip.text ?? { content: '' }), color: event.target.value } })}
                    />
                  </div>
                </div>
              </>
            ) : (
              <div className="rounded-lg border border-dashed border-border p-4 text-sm text-muted-foreground">
                The selected clip is not a text clip.
              </div>
            )}
          </TabsContent>
        )}
      </Tabs>
    </div>
  );
}

import { useEffect } from 'react';
import { isEditableTarget } from '@/tools/video-editor/lib/coordinate-utils';

interface UseKeyboardShortcutsOptions {
  hasSelectedClip: boolean;
  moveSelectedClipToTrack: (direction: 'up' | 'down') => void;
  togglePlayPause: () => void;
  seekRelative: (deltaSeconds: number) => void;
  toggleMute: () => void;
  splitSelectedClip: () => void;
  deleteSelectedClip: () => void;
  clearSelection: () => void;
}

export function useKeyboardShortcuts({
  hasSelectedClip,
  moveSelectedClipToTrack,
  togglePlayPause,
  seekRelative,
  toggleMute,
  splitSelectedClip,
  deleteSelectedClip,
  clearSelection,
}: UseKeyboardShortcutsOptions) {
  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      if (isEditableTarget(event.target)) {
        return;
      }

      if (event.key === 'ArrowLeft') {
        event.preventDefault();
        seekRelative(-1);
        return;
      }

      if (event.key === 'ArrowRight') {
        event.preventDefault();
        seekRelative(1);
        return;
      }

      if (event.key === 'ArrowUp' && hasSelectedClip) {
        event.preventDefault();
        moveSelectedClipToTrack('up');
        return;
      }

      if (event.key === 'ArrowDown' && hasSelectedClip) {
        event.preventDefault();
        moveSelectedClipToTrack('down');
        return;
      }

      if (event.code === 'Space') {
        event.preventDefault();
        togglePlayPause();
        return;
      }

      if (event.key.toLowerCase() === 'm' && hasSelectedClip) {
        event.preventDefault();
        toggleMute();
        return;
      }

      if (event.key.toLowerCase() === 's' && hasSelectedClip) {
        event.preventDefault();
        splitSelectedClip();
        return;
      }

      if ((event.key === 'Backspace' || event.key === 'Delete') && hasSelectedClip) {
        event.preventDefault();
        deleteSelectedClip();
        return;
      }

      if (event.key === 'Escape') {
        event.preventDefault();
        clearSelection();
      }
    };

    window.addEventListener('keydown', onKeyDown);
    return () => window.removeEventListener('keydown', onKeyDown);
  }, [clearSelection, deleteSelectedClip, hasSelectedClip, moveSelectedClipToTrack, seekRelative, splitSelectedClip, toggleMute, togglePlayPause]);
}

