import { useCallback, useEffect, useState } from 'react';
import { useQueryClient } from '@tanstack/react-query';
import { realtimeEventProcessor } from '@/shared/realtime/RealtimeEventProcessor';
import { assetRegistryQueryKey, timelineQueryKey } from '@/tools/video-editor/hooks/useTimeline';
import { timelineListQueryKey } from '@/tools/video-editor/hooks/useTimelinesList';

interface UseTimelineRealtimeOptions {
  timelineId: string;
  saveStatus: 'saved' | 'saving' | 'dirty' | 'error';
  onDiscardRemoteChanges: () => Promise<void>;
}

export function useTimelineRealtime({
  timelineId,
  saveStatus,
  onDiscardRemoteChanges,
}: UseTimelineRealtimeOptions) {
  const queryClient = useQueryClient();
  const [isOpen, setIsOpen] = useState(false);

  useEffect(() => {
    if (saveStatus === 'error') {
      setIsOpen(true);
    }
  }, [saveStatus]);

  useEffect(() => {
    return realtimeEventProcessor.onEvent((event) => {
      if (event.type !== 'timelines-updated') {
        return;
      }

      const matching = event.timelines.find((timeline) => timeline.id === timelineId);
      if (!matching) {
        return;
      }

      if (saveStatus !== 'saved') {
        setIsOpen(true);
        return;
      }

      void queryClient.invalidateQueries({ queryKey: timelineQueryKey(timelineId) });
      void queryClient.invalidateQueries({ queryKey: assetRegistryQueryKey(timelineId) });
      void queryClient.invalidateQueries({ queryKey: timelineListQueryKey(matching.projectId) });
    });
  }, [queryClient, saveStatus, timelineId]);

  const keepLocalChanges = useCallback(() => setIsOpen(false), []);

  const discardAndReload = useCallback(async () => {
    setIsOpen(false);
    await onDiscardRemoteChanges();
    await Promise.all([
      queryClient.invalidateQueries({ queryKey: timelineQueryKey(timelineId) }),
      queryClient.invalidateQueries({ queryKey: assetRegistryQueryKey(timelineId) }),
    ]);
  }, [onDiscardRemoteChanges, queryClient, timelineId]);

  return {
    isOpen,
    setOpen: setIsOpen,
    keepLocalChanges,
    discardAndReload,
  };
}

import { useCallback, useEffect, useMemo, useRef } from 'react';
import type { MutableRefObject } from 'react';
import type {
  DropIndicatorHandle,
  DropIndicatorPosition,
} from '@/tools/video-editor/components/TimelineEditor/DropIndicator';
import {
  computeDropPosition,
  type DropPosition,
} from '@/tools/video-editor/lib/drop-position';
import type { TimelineData } from '@/tools/video-editor/lib/timeline-data';
import type { TrackKind } from '@/tools/video-editor/types';

export interface DragCoordinator {
  update(params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition;
  end(): void;
  lastPosition: DropPosition | null;
}

interface UseDragCoordinatorArgs {
  dataRef: MutableRefObject<TimelineData | null>;
  scale: number;
  scaleWidth: number;
  startLeft: number;
  rowHeight: number;
}

interface UseDragCoordinatorResult {
  coordinator: DragCoordinator;
  indicatorRef: MutableRefObject<DropIndicatorHandle | null>;
  editAreaRef: MutableRefObject<HTMLElement | null>;
}

const buildFallbackPosition = (rowHeight: number, sourceKind: TrackKind | null): DropPosition => ({
  time: 0,
  rowIndex: 0,
  trackId: undefined,
  trackKind: sourceKind,
  trackName: '',
  isNewTrack: false,
  isReject: false,
  newTrackKind: null,
  screenCoords: {
    rowTop: 0,
    rowLeft: 0,
    rowWidth: 0,
    rowHeight,
    clipLeft: 0,
    clipWidth: 0,
    ghostCenter: 0,
  },
});

const toIndicatorPosition = (position: DropPosition): DropIndicatorPosition => {
  const timeLabel = `${position.time.toFixed(1)}s`;
  return {
    rowTop: position.screenCoords.rowTop,
    rowHeight: position.screenCoords.rowHeight,
    rowLeft: position.screenCoords.rowLeft,
    rowWidth: position.screenCoords.rowWidth,
    lineLeft: position.screenCoords.ghostCenter,
    ghostLeft: position.screenCoords.clipLeft,
    ghostTop: position.screenCoords.rowTop + 2,
    ghostWidth: position.screenCoords.clipWidth,
    ghostHeight: Math.max(0, position.screenCoords.rowHeight - 4),
    ghostLabel: timeLabel,
    label: position.trackName ? `${position.trackName} · ${timeLabel}` : timeLabel,
    isNewTrack: position.isNewTrack,
    newTrackKind: position.newTrackKind,
    reject: position.isReject,
  };
};

export function useDragCoordinator({
  dataRef,
  scale,
  scaleWidth,
  startLeft,
  rowHeight,
}: UseDragCoordinatorArgs): UseDragCoordinatorResult {
  const indicatorRef = useRef<DropIndicatorHandle | null>(null);
  const editAreaRef = useRef<HTMLElement | null>(null);
  const lastPositionRef = useRef<DropPosition | null>(null);
  const pendingIndicatorRef = useRef<DropIndicatorPosition | null>(null);
  const frameRef = useRef<number | null>(null);

  const flushIndicator = useCallback(() => {
    frameRef.current = null;
    const pending = pendingIndicatorRef.current;
    if (!pending) {
      return;
    }

    indicatorRef.current?.show(pending);
  }, []);

  const end = useCallback(() => {
    if (frameRef.current !== null) {
      window.cancelAnimationFrame(frameRef.current);
      frameRef.current = null;
    }

    pendingIndicatorRef.current = null;
    lastPositionRef.current = null;
    indicatorRef.current?.hide();
  }, []);

  const update = useCallback((params: {
    clientX: number;
    clientY: number;
    sourceKind: TrackKind | null;
    clipDuration?: number;
    clipOffsetX?: number;
  }): DropPosition => {
    const wrapper = editAreaRef.current?.closest<HTMLDivElement>('.timeline-wrapper');
    if (!wrapper) {
      const fallback = lastPositionRef.current ?? buildFallbackPosition(rowHeight, params.sourceKind);
      lastPositionRef.current = fallback;
      return fallback;
    }

    const nextPosition = computeDropPosition({
      clientX: params.clientX,
      clientY: params.clientY,
      wrapper,
      dataRef,
      scale,
      scaleWidth,
      startLeft,
      rowHeight,
      sourceKind: params.sourceKind,
      clipDuration: params.clipDuration,
      clipOffsetX: params.clipOffsetX,
    });

    lastPositionRef.current = nextPosition;
    pendingIndicatorRef.current = toIndicatorPosition(nextPosition);

    if (frameRef.current === null) {
      frameRef.current = window.requestAnimationFrame(flushIndicator);
    }

    return nextPosition;
  }, [dataRef, flushIndicator, rowHeight, scale, scaleWidth, startLeft]);

  useEffect(() => {
    return () => {
      end();
    };
  }, [end]);

  const coordinator = useMemo<DragCoordinator>(() => ({
    update,
    end,
    get lastPosition() {
      return lastPositionRef.current;
    },
  }), [end, update]);

  return {
    coordinator,
    indicatorRef,
    editAreaRef,
  };
}

import { useCallback, useMemo, useRef } from 'react';
import type { DataProvider } from '@/tools/video-editor/data/DataProvider';
import { DataProviderWrapper } from '@/tools/video-editor/contexts/DataProviderContext';
import { TimelineChromeContextProvider } from '@/tools/video-editor/contexts/TimelineChromeContext';
import { TimelineEditorContextProvider } from '@/tools/video-editor/contexts/TimelineEditorContext';
import { TimelinePlaybackContextProvider } from '@/tools/video-editor/contexts/TimelinePlaybackContext';
