      } else {
        end = start + minDuration;
      }
    }

    const context = getResizeContext(session.actionId, session.rowId);
    if (!context) {
      return;
    }

    const nextAction = {
      ...context.action,
      start,
      end,
    };

    resizePreviewRef.current[session.actionId] = { start, end };
    setResizeOverrides((current) => ({
      ...current,
      [session.actionId]: { start, end },
    }));
